module RefModule (
    input wire clk,
    input wire reset,
    input wire serial_in,
    input wire load,
    output reg [4:0] parallel_out
);
    reg [4:0] unused_shift_reg;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            unused_shift_reg <= 5'b00000;
            parallel_out <= 5'b00000;
        end else if (load) begin
            parallel_out <= unused_shift_reg;
        end else begin
            unused_shift_reg <= {unused_shift_reg[3:0], serial_in}; // Shift left and insert serial input
        end
    end
endmodule
